const DEMO_STEPS_EN = [
  { type: 'user', text: 'Which subsidies are available for our software startup?' },
  { type: 'chip', text: 'Routing to Subsidy Agent...' },
  { type: 'agent', text: 'Sure! I will immediately search for available subsidies for you.' },
  { type: 'panel', actions: [
    { icon: Search, bg: '#6366F1', text: 'RVO.nl searched , 47 relevant schemes found' },
    { icon: Building2, bg: '#3B82F6', text: 'WBSO subsidy identified , up to €40,000/year' },
    { icon: FileText, bg: '#8B5CF6', text: 'MIT subsidy for innovative SME , up to €20,000' },
    { icon: Euro, bg: '#10B981', text: 'Application draft ready , expected 3 weeks processing' },
  ]},
  { type: 'result', text: 'Done: 3 subsidies found, total potential €75,000+' },
];

function SubsidyDemo({ language }) {
  const [step, setStep] = useState(0);
  const [cycle, setCycle] = useState(0);
  const steps = language === 'nl' ? DEMO_STEPS_NL : DEMO_STEPS_EN;

  useEffect(() => {
    setStep(0);
    const timers = [
      setTimeout(() => setStep(1), 800),
      setTimeout(() => setStep(2), 1600),
      setTimeout(() => setStep(3), 2500),
      setTimeout(() => setStep(4), 3300),
      setTimeout(() => setStep(5), 4100),
      setTimeout(() => setStep(6), 5000),
    ];
    const reset = setTimeout(() => setCycle(c => c + 1), 9000);
    return () => { timers.forEach(clearTimeout); clearTimeout(reset); };
  }, [cycle, language]);

  const panelStep = steps.find(s => s.type === 'panel');

  return (
    <DemoWrap
      initial={{ opacity: 0, x: 30 }}
      animate={{ opacity: 1, x: 0 }}
      transition={{ duration: 0.7, delay: 0.3 }}
    >
      <DemoBar>
        <span /><span /><span />
        <span className="title">Optivaize Subsidie Agent</span>
        <span className="live"><span className="liveDot" />LIVE</span>
      </DemoBar>

      <DemoBody>
        <AnimatePresence>
          <ChatRow $user>
            <ChatBubble $user
              initial={{ opacity: 0, y: 6, scale: 0.95 }}
              animate={{ opacity: 1, y: 0, scale: 1 }}
              transition={{ duration: 0.3 }}
            >
              {steps[0].text}
            </ChatBubble>
          </ChatRow>
        </AnimatePresence>

        <AnimatePresence>
          {step >= 1 && (
            <ChatRow>
              <StepChip initial={{ opacity: 0, y: 4 }} animate={{ opacity: 1, y: 0 }}>
                <span style={{ width: 5, height: 5, borderRadius: '50%', background: '#6366F1', flexShrink: 0 }} />
                {steps[1].text}
              </StepChip>
            </ChatRow>
          )}
        </AnimatePresence>

        <AnimatePresence>
          {step >= 2 && (
            <ChatRow>
              <ChatBubble
                initial={{ opacity: 0, y: 6, scale: 0.95 }}
                animate={{ opacity: 1, y: 0, scale: 1 }}
                transition={{ duration: 0.3 }}
                style={{ borderLeft: '2px solid #6366F1' }}
              >
                <span style={{ fontSize: '10px', color: '#A5B4FC', fontWeight: 700, display: 'block', marginBottom: '2px' }}>
                  {language === 'nl' ? 'Subsidie Agent' : 'Subsidy Agent'}
                </span>
                {steps[2].text}
              </ChatBubble>
            </ChatRow>
          )}
        </AnimatePresence>

        <AnimatePresence>
          {step >= 3 && (
            <AgentPanel initial={{ opacity: 0, y: 8 }} animate={{ opacity: 1, y: 0 }}>
              <AgentPanelHeader>
                <span className="pulse" />
                {language === 'nl' ? 'Subsidie Agent , Zoeken & Analyseren' : 'Subsidy Agent , Searching & Analysing'}
              </AgentPanelHeader>
              {panelStep?.actions.map((action, i) => {
                const Icon = action.icon;
                return step >= 3 + i ? (
                  <ActionRow key={i} initial={{ opacity: 0, x: -6 }} animate={{ opacity: 1, x: 0 }} transition={{ duration: 0.25 }}>
                    <ActionIcon $bg={action.bg}><Icon size={11} /></ActionIcon>
                    <ActionText>{action.text}</ActionText>
                    <ActionCheck initial={{ scale: 0 }} animate={{ scale: 1 }} transition={{ type: 'spring', stiffness: 320 }}>✓</ActionCheck>
                  </ActionRow>
                ) : null;
              })}
            </AgentPanel>
          )}
        </AnimatePresence>

        <AnimatePresence>
          {step >= 6 && (
            <ResultBadge initial={{ opacity: 0, y: 6 }} animate={{ opacity: 1, y: 0 }}>
              <CheckCircle size={12} style={{ flexShrink: 0 }} />
              {steps[4].text}
            </ResultBadge>
          )}
        </AnimatePresence>
      </DemoBody>
    </DemoWrap>
  );
}

